import{_ as a,o as t,c as s,a0 as i}from"./chunks/framework.CWk8AOcY.js";const u=JSON.parse('{"title":"Connect to an Existing Cube Cluster","description":"","frontmatter":{},"headers":[],"relativePath":"guide/connect-existing-cluster.md","filePath":"guide/connect-existing-cluster.md"}'),n={name:"guide/connect-existing-cluster.md"};function l(o,e,d,h,p,r){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="connect-to-an-existing-cube-cluster" tabindex="-1">Connect to an Existing Cube Cluster <a class="header-anchor" href="#connect-to-an-existing-cube-cluster" aria-label="Permalink to &quot;Connect to an Existing Cube Cluster&quot;">​</a></h1><p>To get started quickly, check out the example directory:</p><ul><li>Example: <a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar" target="_blank" rel="noreferrer">examples/e2b-dev-sidecar</a></li><li>Chinese README: <a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar/README_zh.md" target="_blank" rel="noreferrer">README_zh.md</a></li><li>English README: <a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar/README.md" target="_blank" rel="noreferrer">README.md</a></li></ul><h2 id="why-we-need-dev-sidecar" tabindex="-1">Why we need <code>dev-sidecar</code> <a class="header-anchor" href="#why-we-need-dev-sidecar" aria-label="Permalink to &quot;Why we need \`dev-sidecar\`&quot;">​</a></h2><p>E2B expects sandbox URLs to resolve to the target cluster&#39;s public IP through wildcard DNS. In a production deployment, that usually means adding a private DNS A record like:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.cube.app =&gt; &lt;your cube master node ip&gt;</span></span></code></pre></div><p>That is inconvenient during local development. Setting up wildcard DNS on a developer machine is usually the annoying part, so <code>dev-sidecar</code> exists to let you connect your local machine to a Cube cluster and create sandboxes without changing the E2B SDK itself.</p><p>This page only does one thing: help you quickly decide how to fill the <code>dev-sidecar</code> environment variables.</p><h2 id="start-with-the-happy-path" tabindex="-1">Start With the Happy Path <a class="header-anchor" href="#start-with-the-happy-path" aria-label="Permalink to &quot;Start With the Happy Path&quot;">​</a></h2><h3 id="case-1-you-started-cube-locally-with-dev-env" tabindex="-1">Case 1: You started Cube locally with <code>dev-env</code> <a class="header-anchor" href="#case-1-you-started-cube-locally-with-dev-env" aria-label="Permalink to &quot;Case 1: You started Cube locally with \`dev-env\`&quot;">​</a></h3><p>This is the most natural and recommended development path for <code>dev-sidecar</code>.</p><p>If you followed <a href="./dev-environment.html">Development Environment (QEMU VM)</a>, the defaults in <code>examples/e2b-dev-sidecar/env.example</code> were already chosen for this exact case.</p><p>Do this:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/e2b-dev-sidecar</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><p>Then usually you only need to fill in the template ID:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:13000&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_REMOTE_PROXY_BASE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://127.0.0.1:11443&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dummy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_TEMPLATE_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;your-template-id&gt;&quot;</span></span></code></pre></div><p>Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.py</span></span></code></pre></div><p>The key point is:</p><ul><li><code>127.0.0.1:13000</code> is not arbitrary. It is the CubeAPI endpoint exposed by <code>dev-env</code>.</li><li><code>127.0.0.1:11443</code> is not arbitrary. It is the CubeProxy endpoint exposed by <code>dev-env</code>.</li></ul><p>So if you already booted local <code>dev-env</code>, you usually do not need to change the addresses. You mostly just fill in the template ID.</p><h3 id="case-2-you-want-to-connect-to-a-cube-cluster-on-another-machine" tabindex="-1">Case 2: You want to connect to a Cube cluster on another machine <a class="header-anchor" href="#case-2-you-want-to-connect-to-a-cube-cluster-on-another-machine" aria-label="Permalink to &quot;Case 2: You want to connect to a Cube cluster on another machine&quot;">​</a></h3><p>You still use the same <code>dev-sidecar</code> example. You only replace the default addresses with the real endpoints of that remote cluster:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://&lt;node-ip&gt;:3000&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_REMOTE_PROXY_BASE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://&lt;node-ip&gt;:443&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E2B_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dummy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_TEMPLATE_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;your-template-id&gt;&quot;</span></span></code></pre></div><p>Then run the same command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.py</span></span></code></pre></div><h2 id="just-remember-these" tabindex="-1">Just Remember These <a class="header-anchor" href="#just-remember-these" aria-label="Permalink to &quot;Just Remember These&quot;">​</a></h2><ul><li><code>E2B_API_URL</code> Control-plane endpoint. In <code>dev-env</code>, the default is <code>http://127.0.0.1:13000</code>.</li><li><code>CUBE_REMOTE_PROXY_BASE</code> Data-plane endpoint. In <code>dev-env</code>, the default is <code>https://127.0.0.1:11443</code>.</li><li><code>E2B_API_KEY</code> Must be non-empty for the SDK. If auth is enabled, use the real key.</li><li><code>CUBE_TEMPLATE_ID</code> The template ID used when creating the sandbox.</li></ul><p>You usually do not need to think about the other variables first. For most development flows, getting these four values right is enough.</p><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><ul><li>You are using local <code>dev-env</code>, but configured the in-VM addresses instead of the host-exposed <code>13000/11443</code> ports</li><li>You pointed <code>CUBE_REMOTE_PROXY_BASE</code> at the sidecar&#39;s own listening address instead of CubeProxy</li><li>You forgot to set <code>CUBE_TEMPLATE_ID</code></li><li>Auth is enabled on the cluster, but <code>E2B_API_KEY</code> is still <code>dummy</code></li></ul><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><p>If you want the easiest explanation, go straight to the example README:</p><ul><li><a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar/README.md" target="_blank" rel="noreferrer">examples/e2b-dev-sidecar/README.md</a></li></ul><p>If you are ready to wire the sidecar into your own code, then look at:</p><ul><li><code>demo.py</code></li><li><code>dev_sidecar.py</code></li></ul>`,36)])])}const k=a(n,[["render",l]]);export{u as __pageData,k as default};
